import React, { useState, useEffect } from "react";
import { useAuth } from '../context/AuthContext';
import axios from 'axios';

export default function FormTratamento({
  denteSelecionado,
  regioesSelecionadas = [],
  onAdicionarTratamento,
  pacienteId
}) {
  const { user } = useAuth();
  const [form, setForm] = useState({
    tratamento: "",
    dente: denteSelecionado || "",
  });
  const [loading, setLoading] = useState(false);

  useEffect(() => {
    setForm(f => ({
      ...f,
      dente: denteSelecionado || "",
    }));
  }, [denteSelecionado]);

  function handleChange(e) {
    const { name, value } = e.target;
    setForm(f => ({ ...f, [name]: value }));
  }

  async function handleSubmit(e) {
    e.preventDefault();
    if (!form.tratamento || !form.dente || regioesSelecionadas.length === 0) return;

    const payload = {
      tratamento: form.tratamento,
      dente: form.dente,
      regioes: regioesSelecionadas.join(','), 
      aluno_id: user.id,
      paciente_id: pacienteId || null,
      status: "aberto"
    };

    try {
      setLoading(true);
      const res = await axios.post('/api/tratamentos', payload);
      if (onAdicionarTratamento) onAdicionarTratamento(res.data);
      setForm({ ...form, tratamento: "", dente: "" });
    } catch (err) {
      alert('Erro ao salvar tratamento');
    } finally {
      setLoading(false);
    }
  }

  return (
    <form onSubmit={handleSubmit} className="bg-gray-50 p-4 rounded shadow mb-4 w-full">
      <div className="flex flex-wrap md:flex-nowrap gap-3 items-end w-full">
        <div className="flex flex-col w-full md:w-[320px]">
          <label className="text-xs text-gray-500 mb-1">Tratamento*</label>
          <input
            name="tratamento"
            className="border rounded px-3 py-2 text-base w-full"
            value={form.tratamento}
            onChange={handleChange}
            required
            autoFocus
            disabled={loading}
            placeholder="Ex: Restauração, Extração..."
          />
        </div>
        <div className="flex flex-col w-20">
          <label className="text-xs text-gray-500 mb-1">Dente*</label>
          <input
            name="dente"
            className="border rounded px-2 py-1 bg-gray-100 w-full"
            value={form.dente}
            readOnly
            required
          />
        </div>
        <div className="flex flex-col w-28">
          <label className="text-xs text-gray-500 mb-1">Regiões*</label>
          <input
            name="regioes"
            className="border rounded px-2 py-1 bg-gray-100 w-full"
            value={regioesSelecionadas.join(', ')}
            readOnly
          />
        </div>
        <div className="flex flex-col w-40">
          <label className="text-xs text-gray-500 mb-1">Profissional</label>
          <input
            className="border rounded px-2 py-1 bg-gray-100 w-full"
            value={user?.nome || ""}
            readOnly
            disabled
            tabIndex={-1}
          />
        </div>
        <button
          type="submit"
          className="bg-green-600 text-white px-4 py-2 rounded font-semibold w-full md:w-auto"
          disabled={regioesSelecionadas.length === 0 || loading}
          style={{ minWidth: 110 }}
        >
          {loading ? 'Salvando...' : 'Adicionar'}
        </button>
      </div>
    </form>
  );
}
